CREATE OR REPLACE FUNCTION to_edate (as_date text,as_format text default 'DD/MM/YYYY') RETURNS timestamp(0) AS $body$
DECLARE

  ls_dd varchar(2);
  ls_mm varchar(2);
  ls_yyyy varchar(4);

BEGIN
  if upper(as_format) = 'DDMMYYYY' then
    -- 31122553
    ls_dd := substr(as_date,1,2);
    ls_mm := substr(as_date,3,2);
    ls_yyyy := (substr(as_date,5,4))::numeric  - 543;
  elsif upper(as_format) in ( 'DD-MM-YYYY','DD/MM/YYYY','DD MM YYYY') then
    ls_dd := substr(as_date,1,2);
    ls_mm := substr(as_date,4,2);
    ls_yyyy := (substr(as_date,7,4))::numeric  - 543;
  elsif upper(as_format) in ( 'YYYY-MM-DD','YYYY/MM/DD','YYYY MM DD') then
    ls_dd := substr(as_date,9,2);
    ls_mm := substr(as_date,6,2);
    ls_yyyy := (substr(as_date,1,4))::numeric  - 543;
  end if;

  return to_date(ls_dd||'/'||ls_mm||'/'||ls_yyyy,'dd/mm/yyyy');

exception when others then return null;
end;
$body$
